SELECT invO.Sap, invO.Tienda, invO.Region, invO.Cedi, invO.Cadena, invO.Clase, invO.Familia, invO.Linea, invO.Presentacion, invO.Marca, invO.Upc, invO.Sku, invO.Producto, invO.Peso, invO.Inv_teorico, invO.Vol_prom, invO.Dme_prom, invO.Merma_porcentaje, invO.Tipo_merma, invO.Venta_promedio, round(invO.DOH,2) AS 'DOH_Actuales', round(invO.Inventario_optimo,0) AS 'Inventario_optimo', ROUND(invO.Inventario_optimo-invO.Inv_teorico,0) AS 'Pedido_minimo_sugerido', ROUND(invO.Inventario_optimo-invO.Inv_teorico,0)* invO.Peso as 'Kilos_pedido_Sugerido'
FROM indicadoresdb.db_owner.mermas_autos_TC_Inventario_optimo invO
WHERE (invO.Clase='RL') AND (invO.Inventario_optimo>Inv_teorico) AND (invO.Presentacion<>'GRANEL') AND (ROUND(invO.Inventario_optimo-invO.Inv_teorico,0)>5) AND (invO.Tipo_merma<>'Critica' And invO.Tipo_merma<>'Inconsistente') AND (invO.Region Is Not Null)
ORDER BY invO.Region, invO.Cedi, invO.Cadena, invO.Sap, invO.Familia, invO.Linea, invO.Presentacion, invO.Marca